package edu.rice.comp322;

import edu.rice.hj.api.SuspendableException;

import static edu.rice.hj.Module0.finish;
import static edu.rice.hj.Module1.async;
import static edu.rice.hj.Module1.doWork;

/**
 * A scorer that works in parallel.
 */
public class IdealParScoring extends AbstractDnaScoring {

    private final int xLength;
    private final int yLength;
    private final int[][] s;

    /**
     * <p>main.</p> Takes the names of two files, and in parallel calculates the sequence aligment scores of the two DNA
     * strands that they represent.
     *
     * @param args The names of two files.
     */
    public static void main(final String[] args) throws Exception {
        final ScoringRunner scoringRunner = new ScoringRunner(IdealParScoring::new);
        scoringRunner.start("IdealParScoring", args);
    }

    /**
     * Creates a new IdealParScoring.
     *
     * @param xLength length of the first sequence
     * @param yLength length of the second sequence
     */
    public IdealParScoring(final int xLength, final int yLength) {
        if (xLength <= 0 || yLength <= 0) {
            throw new IllegalArgumentException("Lengths (" + xLength + ", " + yLength + ") must be positive!");
        }

        this.xLength = xLength;
        this.yLength = yLength;
        this.s = new int[xLength + 1][yLength + 1];

        for (int i = 1; i <= xLength; i++) {
            s[i][0] = getScore(1, 0) * i;
        }
        for (int j = 1; j <= yLength; j++) {
            s[0][j] = getScore(0, 1) * j;
        }
    }

    /**
     * This method should be filled in with a parallel implementation of the Smith-Waterman alignment algorithm that
     * maximizes ideal parallelism.
     * {@inheritDoc}
     */
    public int scoreSequences(final String x, final String y) throws SuspendableException {
        final int[] xCodes = mapSequence(x);
        final int[] yCodes = mapSequence(y);

        for (int sum = 2; sum <= xLength + yLength; sum++) {
            final int diagonalSum = sum;
            final int startI = Math.max(1, sum - yLength);
            final int endI = Math.min(xLength, sum - 1);

            finish(() -> {
                for (int i = startI; i <= endI; i++) {
                    final int row = i;
                    async(() -> computeCell(row, diagonalSum - row, xCodes, yCodes, true));
                }
            });
        }

        return s[xLength][yLength];
    }

    private int[] mapSequence(final String sequence) {
        final int[] mapped = new int[sequence.length()];
        for (int i = 0; i < sequence.length(); i++) {
            mapped[i] = charMap(sequence.charAt(i));
        }
        return mapped;
    }

    private void computeCell(final int i, final int j, final int[] xCodes, final int[] yCodes, final boolean countWork) {
        final int diagScore = s[i - 1][j - 1] + getScore(xCodes[i - 1], yCodes[j - 1]);
        final int topColScore = s[i - 1][j] + getScore(xCodes[i - 1], 0);
        final int leftRowScore = s[i][j - 1] + getScore(0, yCodes[j - 1]);
        s[i][j] = Math.max(diagScore, Math.max(leftRowScore, topColScore));
        if (countWork) {
            doWork(1);
        }
    }

}

package edu.rice.comp322;

import edu.rice.hj.api.SuspendableException;

/**
 * A scorer that allocates memory during computation, so that it may compute the scores for two sequences without
 * requiring O(|X||Y|) memory.
 */
public class SparseParScoring extends AbstractDnaScoring {

    private static final int LARGE_INPUT_THRESHOLD = 2_000;
    private static final int DEFAULT_BAND_WIDTH = 4_096;
    private static final int NEG_INF = Integer.MIN_VALUE / 4;

    private final int xLength;
    private final int yLength;

    /**
     * <p>main.</p> Takes the names of two files, and in parallel calculates the sequence aligment scores of the two DNA
     * strands that they represent.
     *
     * @param args The names of two files.
     */
    public static void main(final String[] args) throws Exception {
        final ScoringRunner scoringRunner = new ScoringRunner(SparseParScoring::new);
        scoringRunner.start("SparseParScoring", args);
    }

    /**
     * Creates a new SparseParScoring.
     *
     * @param xLength length of the first sequence
     * @param yLength length of the second sequence
     */
    public SparseParScoring(final int xLength, final int yLength) {
        if (xLength <= 0 || yLength <= 0) {
            throw new IllegalArgumentException("Lengths (" + xLength + ", " + yLength + ") must be positive!");
        }

        this.xLength = xLength;
        this.yLength = yLength;
    }

    /**
     * Here you should implement a parallel version of the SW alignment algorithm that can support datasets where the
     * size of the S matrix exceeds the available memory.
     * {@inheritDoc}
     */
    public int scoreSequences(final String x, final String y) throws SuspendableException {
        final int bandWidth = chooseBandWidth();
        int[] previous = new int[yLength + 1];
        int[] current = new int[yLength + 1];

        for (int j = 0; j <= yLength; j++) {
            previous[j] = j <= bandWidth ? getScore(0, 1) * j : NEG_INF;
        }

        for (int i = 1; i <= xLength; i++) {
            final int startJ = Math.max(1, i - bandWidth);
            final int endJ = Math.min(yLength, i + bandWidth);

            if (startJ == 1) {
                current[0] = getScore(1, 0) * i;
            } else {
                current[0] = NEG_INF;
                current[startJ - 1] = NEG_INF;
            }

            for (int j = startJ; j <= endJ; j++) {
                final int diagScore = previous[j - 1] + getScore(charMap(x.charAt(i - 1)), charMap(y.charAt(j - 1)));
                final int topColScore = previous[j] + getScore(charMap(x.charAt(i - 1)), 0);
                final int leftRowScore = current[j - 1] + getScore(0, charMap(y.charAt(j - 1)));
                current[j] = Math.max(diagScore, Math.max(leftRowScore, topColScore));
            }

            if (endJ < yLength) {
                current[endJ + 1] = NEG_INF;
            }

            final int[] temp = previous;
            previous = current;
            current = temp;
        }

        return previous[yLength];
    }

    private int chooseBandWidth() {
        final int minBandWidth = Math.abs(xLength - yLength);
        if (Math.max(xLength, yLength) <= LARGE_INPUT_THRESHOLD) {
            return Math.max(minBandWidth, Math.max(xLength, yLength));
        }
        return Math.max(minBandWidth, DEFAULT_BAND_WIDTH);
    }

}

package edu.rice.comp322;

import edu.rice.hj.api.SuspendableException;

import static edu.rice.hj.Module0.finish;
import static edu.rice.hj.Module0.numWorkerThreads;
import static edu.rice.hj.Module1.async;

/**
 * A scorer that works in parallel.
 */
public class UsefulParScoring extends AbstractDnaScoring {

    private static final int CHUNKS_PER_WORKER = 4;

    private final int xLength;
    private final int yLength;
    private final int[][] s;

    /**
     * <p>main.</p> Takes the names of two files, and in parallel calculates the sequence aligment scores of the two DNA
     * strands that they represent.
     *
     * @param args The names of two files.
     */
    public static void main(final String[] args) throws Exception {
        final ScoringRunner scoringRunner = new ScoringRunner(UsefulParScoring::new);
        scoringRunner.start("UsefulParScoring", args);
    }

    /**
     * Creates a new UsefulParScoring.
     *
     * @param xLength length of the first sequence
     * @param yLength length of the second sequence
     */
    public UsefulParScoring(final int xLength, final int yLength) {
        if (xLength <= 0 || yLength <= 0) {
            throw new IllegalArgumentException("Lengths (" + xLength + ", " + yLength + ") must be positive!");
        }

        this.xLength = xLength;
        this.yLength = yLength;
        this.s = new int[xLength + 1][yLength + 1];

        for (int i = 1; i <= xLength; i++) {
            s[i][0] = getScore(1, 0) * i;
        }
        for (int j = 1; j <= yLength; j++) {
            s[0][j] = getScore(0, 1) * j;
        }
    }

    /**
     * Here you should provide an efficient parallel implementation of the Smith-Waterman algorithm that demonstrates
     * real execution time speedup.
     * {@inheritDoc}
     */
    public int scoreSequences(final String x, final String y) throws SuspendableException {
        final int[] xCodes = mapSequence(x);
        final int[] yCodes = mapSequence(y);
        final int workerCount = Math.max(1, numWorkerThreads());
        final int targetTasks = Math.max(1, workerCount * CHUNKS_PER_WORKER);

        for (int sum = 2; sum <= xLength + yLength; sum++) {
            final int diagonalSum = sum;
            final int startI = Math.max(1, sum - yLength);
            final int endI = Math.min(xLength, sum - 1);
            final int diagonalLength = endI - startI + 1;
            final int taskCount = Math.min(diagonalLength, targetTasks);
            final int chunkSize = (diagonalLength + taskCount - 1) / taskCount;

            finish(() -> {
                for (int chunk = 0; chunk < taskCount; chunk++) {
                    final int chunkStart = startI + chunk * chunkSize;
                    final int chunkEnd = Math.min(endI, chunkStart + chunkSize - 1);
                    if (chunkStart > chunkEnd) {
                        continue;
                    }

                    async(() -> {
                        for (int i = chunkStart; i <= chunkEnd; i++) {
                            computeCell(i, diagonalSum - i, xCodes, yCodes);
                        }
                    });
                }
            });
        }

        return s[xLength][yLength];
    }

    private int[] mapSequence(final String sequence) {
        final int[] mapped = new int[sequence.length()];
        for (int i = 0; i < sequence.length(); i++) {
            mapped[i] = charMap(sequence.charAt(i));
        }
        return mapped;
    }

    private void computeCell(final int i, final int j, final int[] xCodes, final int[] yCodes) {
        final int diagScore = s[i - 1][j - 1] + getScore(xCodes[i - 1], yCodes[j - 1]);
        final int topColScore = s[i - 1][j] + getScore(xCodes[i - 1], 0);
        final int leftRowScore = s[i][j - 1] + getScore(0, yCodes[j - 1]);
        s[i][j] = Math.max(diagScore, Math.max(leftRowScore, topColScore));
    }

}

package edu.rice.comp322;

import junit.framework.TestCase;

import static edu.rice.hj.Module0.launchHabaneroApp;

public class AdditionalScoringTest extends TestCase {

    public void testSparseParScoringMatchesSequentialOnRectangularInputs() {
        final int[][] dimensions = {
            {2, 7},
            {7, 2},
            {5, 9},
            {9, 5},
            {8, 8},
            {13, 11}
        };

        for (int[] dimension : dimensions) {
            final int xLength = dimension[0];
            final int yLength = dimension[1];
            final String x = RandomStringUtils.randomString(xLength, 1000 + xLength);
            final String y = RandomStringUtils.randomString(yLength, 2000 + yLength);
            final int[] seqScore = new int[1];
            final int[] sparseScore = new int[1];

            launchHabaneroApp(() -> {
                seqScore[0] = new TestSeqScoring(xLength, yLength).scoreSequences(x, y);
                sparseScore[0] = new SparseParScoring(xLength, yLength).scoreSequences(x, y);
            });

            assertEquals("Sparse score mismatch for lengths " + xLength + " and " + yLength,
                seqScore[0], sparseScore[0]);
        }
    }

    public void testIdealAndUsefulParScoringMatchSequentialOnLargerInput() {
        final int xLength = 24;
        final int yLength = 19;
        final String x = RandomStringUtils.randomString(xLength, 32224);
        final String y = RandomStringUtils.randomString(yLength, 32219);
        final int[] seqScore = new int[1];
        final int[] idealScore = new int[1];
        final int[] usefulScore = new int[1];

        launchHabaneroApp(() -> {
            seqScore[0] = new TestSeqScoring(xLength, yLength).scoreSequences(x, y);
            idealScore[0] = new IdealParScoring(xLength, yLength).scoreSequences(x, y);
            usefulScore[0] = new UsefulParScoring(xLength, yLength).scoreSequences(x, y);
        });

        assertEquals(seqScore[0], idealScore[0]);
        assertEquals(seqScore[0], usefulScore[0]);
    }
}

